import React, { useState } from 'react';
import { formatDate } from '../../data/bookingStore.js';
import ConfirmModal from './ConfirmModal.jsx';
import styles from '../../styles/admin/BookingsTable.module.css';

const STATUS_COLORS = {
  confirmed: styles.statusConfirmed,
  cancelled: styles.statusCancelled,
  pending:   styles.statusPending,
};

const BookingsTable = ({ bookings, onTogglePaid, onCancelBooking }) => {
  const [filter,     setFilter]     = useState('all');
  const [search,     setSearch]     = useState('');
  const [expandedId, setExpandedId] = useState(null);

  // Modal state
  const [modal, setModal] = useState({
    isOpen:  false,
    type:    'warning',
    title:   '',
    message: '',
    onConfirm: null,
  });

  const openModal = ({ type, title, message, onConfirm }) => {
    setModal({ isOpen: true, type, title, message, onConfirm });
  };

  const closeModal = () => {
    setModal(prev => ({ ...prev, isOpen: false, onConfirm: null }));
  };

  const handleModalConfirm = () => {
    if (modal.onConfirm) modal.onConfirm();
    closeModal();
  };

  // Ask before cancel
  const handleCancelClick = (b) => {
    openModal({
      type:    'cancel',
      title:   'Cancel Booking?',
      message: `You are about to cancel the booking of ${b.guestName} (${b.id}). This action cannot be undone.`,
      onConfirm: () => onCancelBooking(b.id),
    });
  };

  // Ask before toggle paid
  const handlePaidClick = (b) => {
    openModal({
      type:    b.paid ? 'warning' : 'edit',
      title:   b.paid ? 'Mark as Unpaid?' : 'Mark as Paid?',
      message: b.paid
        ? `This will mark ${b.guestName}'s booking as unpaid. You can change this anytime.`
        : `This will mark ${b.guestName}'s booking (₱${b.total.toLocaleString()}) as paid. Please confirm.`,
      onConfirm: () => onTogglePaid(b.id),
    });
  };

  const filtered = bookings.filter(b => {
    const matchFilter =
      filter === 'all' ||
      (filter === 'paid'      &&  b.paid) ||
      (filter === 'unpaid'    && !b.paid) ||
      (filter === 'cancelled' && b.status === 'cancelled') ||
      (filter === 'confirmed' && b.status === 'confirmed');
    const contact = b.guestContact || '';
    const matchSearch = !search ||
      b.guestName.toLowerCase().includes(search.toLowerCase()) ||
      b.id.toLowerCase().includes(search.toLowerCase()) ||
      contact.toLowerCase().includes(search.toLowerCase());
    return matchFilter && matchSearch;
  });

  return (
    <>
      <ConfirmModal
        isOpen={modal.isOpen}
        type={modal.type}
        title={modal.title}
        message={modal.message}
        onConfirm={handleModalConfirm}
        onCancel={closeModal}
      />

      <div className={styles.wrapper}>
        <div className={styles.toolbar}>
          <div className={styles.filters}>
            {['all','confirmed','cancelled','paid','unpaid'].map(f => (
              <button key={f}
                className={`${styles.filterBtn} ${filter === f ? styles.active : ''}`}
                onClick={() => setFilter(f)} type="button">
                {f.charAt(0).toUpperCase() + f.slice(1)}
              </button>
            ))}
          </div>
          <input className={styles.search} type="text"
            placeholder="Search name, contact, ref code…"
            value={search} onChange={e => setSearch(e.target.value)} />
        </div>

        {filtered.length === 0 ? (
          <div className={styles.empty}><span>🌸</span><p>No bookings found.</p></div>
        ) : (
          <div className={styles.tableWrap}>
            <table className={styles.table}>
              <thead>
                <tr>
                  <th>Ref Code</th><th>Guest</th><th>Type</th>
                  <th>Check-in</th><th>Check-out</th><th>Nights</th>
                  <th>Total</th><th>Payment</th><th>Status</th><th>Actions</th>
                </tr>
              </thead>
              <tbody>
                {filtered.map(b => {
                  const contact      = b.guestContact || '';
                  const isMessenger  = b.contactMethod === 'messenger';
                  const messengerUrl = contact
                    ? (contact.startsWith('http') ? contact : `https://${contact}`)
                    : null;

                  return (
                    <React.Fragment key={b.id}>
                      <tr
                        className={`${styles.row} ${b.status === 'cancelled' ? styles.rowCancelled : ''}`}
                        onClick={() => setExpandedId(expandedId === b.id ? null : b.id)}
                      >
                        <td><span className={styles.refCode}>{b.id}</span></td>
                        <td>
                          <div className={styles.guestName}>{b.guestName}</div>
                          <div className={styles.guestEmail}>
                            {isMessenger
                              ? <span className={styles.messengerTag}>💬 Messenger</span>
                              : contact}
                          </div>
                        </td>
                        <td><span className={styles.roomTag}>{b.room?.icon} {b.room?.name}</span></td>
                        <td className={styles.date}>{formatDate(b.checkIn)}</td>
                        <td className={styles.date}>{b.checkOut ? formatDate(b.checkOut) : '—'}</td>
                        <td className={styles.center}>{b.nights > 0 ? `${b.nights}N` : '—'}</td>
                        <td className={styles.total}>₱{(b.total || 0).toLocaleString()}</td>

                        {/* Payment — asks confirmation */}
                        <td onClick={e => e.stopPropagation()}>
                          <button
                            className={`${styles.paidBtn} ${b.paid ? styles.paidYes : styles.paidNo}`}
                            onClick={() => handlePaidClick(b)}
                            type="button"
                            title="Click to change payment status"
                          >
                            {b.paid ? '✓ Paid' : '✗ Unpaid'}
                          </button>
                        </td>

                        <td>
                          <span className={`${styles.statusBadge} ${STATUS_COLORS[b.status] || ''}`}>
                            {b.status}
                          </span>
                        </td>

                        {/* Actions */}
                        <td onClick={e => e.stopPropagation()}>
                          <div className={styles.actionGroup}>
                            {isMessenger && messengerUrl && (
                              <a href={messengerUrl} target="_blank" rel="noopener noreferrer"
                                className={styles.messengerBtn}>
                                💬 Open
                              </a>
                            )}
                            {b.status !== 'cancelled' && (
                              <button
                                className={styles.cancelBtn}
                                onClick={() => handleCancelClick(b)}
                                type="button"
                              >
                                Cancel
                              </button>
                            )}
                          </div>
                        </td>
                      </tr>

                      {/* Expanded row */}
                      {expandedId === b.id && (
                        <tr className={styles.expandedRow}>
                          <td colSpan={10}>
                            <div className={styles.expandedContent}>
                              <div className={styles.expandedItem}>
                                <span className={styles.expandLabel}>Guests</span>
                                <span>{b.guests} pax</span>
                              </div>
                              <div className={styles.expandedItem}>
                                <span className={styles.expandLabel}>Contact</span>
                                <span>
                                  {isMessenger && messengerUrl
                                    ? <a href={messengerUrl} target="_blank" rel="noopener noreferrer"
                                        className={styles.messengerLink}>{contact}</a>
                                    : contact}
                                </span>
                              </div>
                              <div className={styles.expandedItem}>
                                <span className={styles.expandLabel}>Booked On</span>
                                <span>{new Date(b.createdAt).toLocaleString('en-PH')}</span>
                              </div>
                              <div className={styles.expandedItem}>
                                <span className={styles.expandLabel}>Special Requests</span>
                                <span>{b.specialRequests || <em>None</em>}</span>
                              </div>
                            </div>
                          </td>
                        </tr>
                      )}
                    </React.Fragment>
                  );
                })}
              </tbody>
            </table>
          </div>
        )}

        <div className={styles.tableFooter}>
          Showing {filtered.length} of {bookings.length} bookings
        </div>
      </div>
    </>
  );
};

export default BookingsTable;
